import type { Config } from 'tailwindcss';

const config: Config = {
  darkMode: ['class'],
  content: [
    './src/pages/**/*.{js,ts,jsx,tsx,mdx}',
    './src/components/**/*.{js,ts,jsx,tsx,mdx}',
    './src/app/**/*.{js,ts,jsx,tsx,mdx}',
  ],
  theme: {
    container: {
      center: true,
      padding: {
        DEFAULT: '1rem',
        sm: '1.5rem',
        lg: '2rem',
      },
      screens: {
        sm: '640px',
        md: '768px',
        lg: '1024px',
        xl: '1280px',
        '2xl': '1536px',
      },
    },
    extend: {
      colors: {
        // Full Miami Vice brand palette
        brand: {
          // Neon colors (primary in dark mode)
          pink: '#ff0080',
          'pink-dark': '#cc0066',
          'pink-light': '#ff3399',
          cyan: '#00f0ff',
          'cyan-dark': '#00c0cc',
          'cyan-light': '#33f5ff',
          purple: '#9b59ff',
          'purple-dark': '#7c47cc',
          'purple-light': '#b080ff',
          // Sunset colors (primary in light mode)
          orange: '#ff7033',
          'orange-dark': '#cc5929',
          'orange-light': '#ff8f5c',
          yellow: '#ffbf00',
          'yellow-dark': '#cc9900',
          'yellow-light': '#ffcc33',
          coral: '#ff6b6b',
          'coral-dark': '#cc5656',
          'coral-light': '#ff8989',
        },
        // Semantic colors using CSS variables
        background: 'hsl(var(--background))',
        foreground: 'hsl(var(--foreground))',
        card: {
          DEFAULT: 'hsl(var(--card))',
          foreground: 'hsl(var(--card-foreground))',
        },
        popover: {
          DEFAULT: 'hsl(var(--popover))',
          foreground: 'hsl(var(--popover-foreground))',
        },
        primary: {
          DEFAULT: 'hsl(var(--primary))',
          foreground: 'hsl(var(--primary-foreground))',
        },
        secondary: {
          DEFAULT: 'hsl(var(--secondary))',
          foreground: 'hsl(var(--secondary-foreground))',
        },
        muted: {
          DEFAULT: 'hsl(var(--muted))',
          foreground: 'hsl(var(--muted-foreground))',
        },
        accent: {
          DEFAULT: 'hsl(var(--accent))',
          foreground: 'hsl(var(--accent-foreground))',
        },
        destructive: {
          DEFAULT: 'hsl(var(--destructive))',
          foreground: 'hsl(var(--destructive-foreground))',
        },
        border: 'hsl(var(--border))',
        input: 'hsl(var(--input))',
        ring: 'hsl(var(--ring))',
        chart: {
          '1': 'hsl(var(--chart-1))',
          '2': 'hsl(var(--chart-2))',
          '3': 'hsl(var(--chart-3))',
          '4': 'hsl(var(--chart-4))',
          '5': 'hsl(var(--chart-5))',
        },
      },
      borderRadius: {
        lg: 'var(--radius)',
        md: 'calc(var(--radius) - 2px)',
        sm: 'calc(var(--radius) - 4px)',
      },
      fontFamily: {
        sans: ['var(--font-sans)', 'system-ui', 'sans-serif'],
        mono: ['var(--font-mono)', 'monospace'],
      },
      keyframes: {
        'fade-in': {
          '0%': { opacity: '0' },
          '100%': { opacity: '1' },
        },
        'fade-up': {
          '0%': { opacity: '0', transform: 'translateY(10px)' },
          '100%': { opacity: '1', transform: 'translateY(0)' },
        },
        'slide-in-right': {
          '0%': { transform: 'translateX(100%)' },
          '100%': { transform: 'translateX(0)' },
        },
        'pulse-glow': {
          '0%, 100%': {
            boxShadow: '0 0 20px hsl(var(--brand-primary) / 0.3)',
          },
          '50%': {
            boxShadow: '0 0 40px hsl(var(--brand-primary) / 0.6)',
          },
        },
        shimmer: {
          '0%': { backgroundPosition: '-200% 0' },
          '100%': { backgroundPosition: '200% 0' },
        },
      },
      animation: {
        'fade-in': 'fade-in 0.3s ease-out',
        'fade-up': 'fade-up 0.4s ease-out',
        'slide-in-right': 'slide-in-right 0.3s ease-out',
        'pulse-glow': 'pulse-glow 2s ease-in-out infinite',
        shimmer: 'shimmer 2s linear infinite',
      },
      backgroundImage: {
        // Neon gradients (dark mode favorites)
        'gradient-miami': 'linear-gradient(135deg, #ff0080 0%, #00f0ff 100%)',
        'gradient-neon': 'linear-gradient(135deg, #00f0ff 0%, #ff0080 50%, #9b59ff 100%)',
        // Sunset gradients (light mode favorites)
        'gradient-sunset': 'linear-gradient(135deg, #ff7033 0%, #ff6b6b 50%, #ff0080 100%)',
        'gradient-golden': 'linear-gradient(135deg, #ffbf00 0%, #ff7033 100%)',
        // Universal
        'gradient-rainbow': 'linear-gradient(135deg, #ff0080, #ff7033, #ffbf00, #00f0ff, #9b59ff)',
      },
    },
  },
  plugins: [],
};

export default config;

/**
 * CENTRALIZED THEME CONFIGURATION
 * ================================
 * Change colors here to update the entire platform.
 * Colors are defined in both HEX and HSL formats.
 *
 * Miami Vice Color Palette:
 * - The palette adapts based on light/dark mode
 * - Light mode: Warmer sunset tones (orange, coral, yellow)
 * - Dark mode: Neon electric tones (pink, cyan, purple)
 *
 * To change the color scheme:
 * 1. Update the HEX values in this file
 * 2. Update globals.css with corresponding HSL values
 * 3. Update tailwind.config.ts if adding new named colors
 */

// Full Miami Vice Palette
export const brandColors = {
  // Primary neon colors (used more in dark mode)
  pink: {
    hex: '#ff0080',
    hsl: '330 100% 50%',
    rgb: '255, 0, 128',
  },
  cyan: {
    hex: '#00f0ff',
    hsl: '184 100% 50%',
    rgb: '0, 240, 255',
  },
  purple: {
    hex: '#9b59ff',
    hsl: '270 70% 60%',
    rgb: '155, 89, 255',
  },

  // Warm sunset colors (used more in light mode)
  orange: {
    hex: '#ff7033',
    hsl: '25 100% 55%',
    rgb: '255, 112, 51',
  },
  yellow: {
    hex: '#ffbf00',
    hsl: '45 100% 55%',
    rgb: '255, 191, 0',
  },
  coral: {
    hex: '#ff6b6b',
    hsl: '10 100% 65%',
    rgb: '255, 107, 107',
  },
} as const;

// Theme-specific color assignments
export const themeConfig = {
  light: {
    // Light mode uses warmer colors
    primary: brandColors.coral,
    secondary: brandColors.orange,
    accent: brandColors.yellow,

    // Background tones
    background: { hex: '#fdfcfa', hsl: '30 30% 98%' },
    foreground: { hex: '#1a1a1a', hsl: '240 10% 10%' },
    card: { hex: '#fefefe', hsl: '30 20% 99%' },
    muted: { hex: '#f5f3f0', hsl: '30 15% 94%' },
    border: { hex: '#e5e2de', hsl: '30 15% 88%' },
  },
  dark: {
    // Dark mode uses neon colors
    primary: brandColors.pink,
    secondary: brandColors.cyan,
    accent: brandColors.purple,

    // Background tones
    background: { hex: '#0a0a0f', hsl: '240 15% 4%' },
    foreground: { hex: '#fafafa', hsl: '0 0% 98%' },
    card: { hex: '#111118', hsl: '240 15% 6%' },
    muted: { hex: '#27272a', hsl: '240 5% 16%' },
    border: { hex: '#2e2e33', hsl: '240 5% 18%' },
  },
} as const;

// Gradient definitions
export const gradients = {
  // Theme-adaptive gradients (use CSS variables)
  primary: 'linear-gradient(135deg, hsl(var(--brand-primary)) 0%, hsl(var(--brand-secondary)) 100%)',
  accent: 'linear-gradient(135deg, hsl(var(--brand-primary)) 0%, hsl(var(--brand-accent)) 100%)',

  // Static gradients
  miami: `linear-gradient(135deg, ${brandColors.pink.hex} 0%, ${brandColors.cyan.hex} 100%)`,
  sunset: `linear-gradient(135deg, ${brandColors.orange.hex} 0%, ${brandColors.coral.hex} 50%, ${brandColors.pink.hex} 100%)`,
  neon: `linear-gradient(135deg, ${brandColors.cyan.hex} 0%, ${brandColors.pink.hex} 50%, ${brandColors.purple.hex} 100%)`,
  golden: `linear-gradient(135deg, ${brandColors.yellow.hex} 0%, ${brandColors.orange.hex} 100%)`,
} as const;

// Export for easy access
export const COLORS = {
  PINK: brandColors.pink.hex,
  CYAN: brandColors.cyan.hex,
  PURPLE: brandColors.purple.hex,
  ORANGE: brandColors.orange.hex,
  YELLOW: brandColors.yellow.hex,
  CORAL: brandColors.coral.hex,
} as const;

// Helper to get CSS variable value
export function cssVar(name: string): string {
  return `hsl(var(--${name}))`;
}

// Chart color palette
export const chartColors = {
  light: [
    brandColors.orange.hex,
    brandColors.yellow.hex,
    brandColors.coral.hex,
    brandColors.pink.hex,
    brandColors.purple.hex,
  ],
  dark: [
    brandColors.pink.hex,
    brandColors.cyan.hex,
    brandColors.purple.hex,
    brandColors.orange.hex,
    brandColors.yellow.hex,
  ],
} as const;

